package dev.modichamiya.eclipse.gameplay.economy;

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

public final class LedgerService {public record Entry(UUID transaction,UUID account,String currency,long delta,long balance){}private final Map<UUID,Map<String,Long>>balances=new ConcurrentHashMap<>();private final List<Entry>journal=new ArrayList<>();public synchronized long balance(UUID account,String currency){return balances.getOrDefault(account,Map.of()).getOrDefault(currency,0L);}public synchronized UUID transfer(UUID from,UUID to,String currency,long amount){if(amount<=0)throw new IllegalArgumentException();long source=balance(from,currency);if(source<amount)throw new IllegalStateException("Insufficient funds");UUID transaction=UUID.randomUUID();set(from,currency,source-amount,transaction,-amount);long target=Math.addExact(balance(to,currency),amount);set(to,currency,target,transaction,amount);return transaction;}public synchronized void mint(UUID account,String currency,long amount){if(amount<0)throw new IllegalArgumentException();set(account,currency,Math.addExact(balance(account,currency),amount),UUID.randomUUID(),amount);}private void set(UUID account,String currency,long balance,UUID transaction,long delta){balances.computeIfAbsent(account,id->new ConcurrentHashMap<>()).put(currency,balance);journal.add(new Entry(transaction,account,currency,delta,balance));}public synchronized List<Entry>journal(){return List.copyOf(journal);}}
